/**
* 字符串是否含有html标签的检测
* @param htmlStr
*/
export function checkHtml(htmlStr) {
    var reg = /<[^>]+>/g;
    return reg.test(htmlStr);
}

export function getHtmlPlainText(html_str) {
    //提取字符串中的文字
    let re = new RegExp('/(?=>)(.|\s)?(?=</?\w+[^<]>)/', 'g')
    let text = html_str.replace(re, '')
    //或
    //var text = html_str.replace(/<[^<>]+>/g, "");
    return text
}

